fn solve(n: i64, edges: Vec<Vec<i64>>, k: i64) -> i64 {
    let n = n as usize;
    let mut edges: Vec<Vec<i64>> = edges;
    edges.sort_by(|a, b| a[2].cmp(&b[2]));

    let mut low = 0;
    let mut high = edges.len() - 1;
    let mut answer = i64::MAX;

    fn find(parent: &mut Vec<usize>, x: usize) -> usize {
        if parent[x] != x {
            parent[x] = find(parent, parent[x]);
        }
        parent[x]
    }

    fn union(parent: &mut Vec<usize>, rank: &mut Vec<usize>, x: usize, y: usize) {
        let x_root = find(parent, x);
        let y_root = find(parent, y);
        if x_root == y_root {
            return;
        }
        if rank[x_root] < rank[y_root] {
            parent[x_root] = y_root;
        } else {
            parent[y_root] = x_root;
            if rank[x_root] == rank[y_root] {
                rank[x_root] += 1;
            }
        }
