fn solve(n: i64, edges: Vec<Vec<i64>>, k: i64) -> i64 {
    struct DSU {
        parent: Vec<usize>,
        rank: Vec<usize>,
    }

    impl DSU {
        fn new(n: usize) -> Self {
            let parent = (0..n).map(|i| i).collect();
            let rank = vec![1; n];
            DSU { parent, rank }
        }

        fn find(&mut self, x: usize) -> usize {
            if self.parent[x] != x {
                self.parent[x] = self.find(self.parent[x]);
            }
            self.parent[x]
        }

        fn union(&mut self, x: usize, y: usize) {
            let x_root = self.find(x);
            let y_root = self.find(y);
            if x_root == y_root {
                return;
            }
            if self.rank[x_root] < self.rank[y_root] {
                self.parent[x_root] = y_root;
            } else {
                self.parent[y_root] = x_root;
                if self.rank[x_root] == self.rank[y_root] {
                    self.rank[x_root] += 1;
                }
            }
        }

        fn count_components(&mut self) -> usize {
            let mut roots = vec![false; self.parent.len()];
            let mut count = 0;
            for i in 0..self.parent.len() {
                let root = self.find(i);
                if !roots[root] {
                    roots[root] = true;
                    count += 1;
                }
            }
            count
        }
    }

    let n = n as usize;
    let mut edges_sorted = edges;
    edges_sorted.sort_by(|a, b| a[2].cmp(&b[2]));
    let mut low = 0;
    let mut high = edges_sorted.iter().map(|e| e[2]).max().unwrap() as i64;
    let mut answer = high;
    while low <= high {
        let mid = (low + high) / 2;
        let mut dsu = DSU::new(n);
        for edge in &edges_sorted {
            if edge[2] <= mid {
                dsu.union(edge[0] as usize, edge[1] as usize);
            }
        }
        let components = dsu.count_components();
        if components <= k {
            answer = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }
    answer
}
